// === Preparar Paths ===
// Concatena todos os clips com transicoes crossfade (xfade/acrossfade),
// sobrepoe a logo DJE e um overlay de CTA, gerando o video final vertical.
// ENHANCEMENT 3: opcionalmente mixa uma musica de fundo em volume baixo sob toda a narracao.
// ASYNC: usa exec promisificado (await) para nao bloquear o event loop do task runner.
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const EXEC_OPTS = { timeout: 300000, maxBuffer: 1024 * 1024 * 128 };
const NL = String.fromCharCode(10);
const BS = String.fromCharCode(92);
const TMP = '/tmp';

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(idx, prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(idx, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

const items = $input.all();
const clipPaths = [];
let articleTitle = 'video_dje';
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  if (items[i].json && items[i].json.articleTitle) articleTitle = items[i].json.articleTitle;
  const buf = await getBuf.call(this, i, 'data', bin);
  if (!buf) continue;
  const p = `${TMP}/seg_${i}.mp4`;
  fs.writeFileSync(p, buf);
  clipPaths.push(p);
}

if (clipPaths.length === 0) {
  throw new Error('Nenhum clip disponivel para concatenar.');
}

// baixa a logo DJE branca (User-Agent de navegador)
const logoPath = `${TMP}/logo_dje.png`;
try {
  await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${logoPath}" "https://construcao.djereformas.com.br/wp-content/uploads/2026/03/logo-DJE-branco.png"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
} catch (e) {}
const temLogo = (function () { try { return fs.existsSync(logoPath) && fs.statSync(logoPath).size > 0; } catch (e) { return false; } })();

const FONT = (function () {
  const fontes = [
    '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf'
  ];
  for (const f of fontes) { try { if (fs.existsSync(f)) return f; } catch (e) {} }
  return null;
})();
const fontPart = FONT ? `fontfile='${FONT}':` : '';
const ctaText = 'Orcamento gratis' + BS + ': WhatsApp (11) 5891.6837';
const ctaDraw = `drawtext=${fontPart}text='${ctaText}':fontcolor=white:fontsize=48:box=1:boxcolor=black@0.6:boxborderw=18:x=(w-text_w)/2:y=h*0.06:enable='gte(t,0)'`;

const XF = 0.5; // duracao do crossfade
let finalPath = `${TMP}/final_${Date.now()}.mp4`;

async function probeDur(p) {
  try {
    const r = await execAsync('ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + p + '"', { timeout: 60000, maxBuffer: 1024 * 1024 * 16 });
    const d = parseFloat(String(r.stdout).trim());
    return (!isNaN(d) && d > 0) ? d : 4;
  } catch (e) { return 4; }
}

let sucesso = false;
try {
  const inputs = clipPaths.map(p => `-i "${p}"`).join(' ');
  let filter = '';
  let vlast, alast;

  if (clipPaths.length === 1) {
    vlast = '[0:v]';
    alast = '[0:a]';
  } else {
    const durs = [];
    for (const cp of clipPaths) { durs.push(await probeDur(cp)); }
    vlast = '[0:v]';
    alast = '[0:a]';
    let offset = durs[0] - XF;
    for (let i = 1; i < clipPaths.length; i++) {
      const vout = `[v${i}]`;
      const aout = `[a${i}]`;
      filter += `${vlast}[${i}:v]xfade=transition=fade:duration=${XF}:offset=${offset.toFixed(3)}${vout};`;
      filter += `${alast}[${i}:a]acrossfade=d=${XF}${aout};`;
      vlast = vout;
      alast = aout;
      offset += durs[i] - XF;
    }
  }

  // overlay da logo + CTA
  const logoIdx = clipPaths.length;
  let videoChain = vlast;
  if (temLogo) {
    filter += `[${logoIdx}:v]scale=320:-1[lg];${videoChain}[lg]overlay=W-w-40:H-h-60[vlogo];`;
    videoChain = '[vlogo]';
  }
  filter += `${videoChain}${ctaDraw}[vout]`;

  const logoInput = temLogo ? `-i "${logoPath}"` : '';
  await execAsync(`ffmpeg -y ${inputs} ${logoInput} -filter_complex "${filter}" -map "[vout]" -map "${alast}" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  sucesso = fs.existsSync(finalPath);
} catch (e) {
  sucesso = false;
}

// fallback: concat demuxer simples + logo/CTA se o xfade falhar
if (!sucesso) {
  const listPath = `${TMP}/concat_list.txt`;
  fs.writeFileSync(listPath, clipPaths.map(p => `file '${p}'`).join(NL));
  const concatPath = `${TMP}/concat_${Date.now()}.mp4`;
  await execAsync(`ffmpeg -y -f concat -safe 0 -i "${listPath}" -c copy "${concatPath}"`, EXEC_OPTS);
  if (temLogo) {
    await execAsync(`ffmpeg -y -i "${concatPath}" -i "${logoPath}" -filter_complex "[1:v]scale=320:-1[lg];[0:v][lg]overlay=W-w-40:H-h-60[vl];[vl]${ctaDraw}[vout]" -map "[vout]" -map 0:a -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  } else {
    await execAsync(`ffmpeg -y -i "${concatPath}" -vf "${ctaDraw}" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  }
}

// === ENHANCEMENT 3: musica de fundo opcional (volume baixo sob a narracao) ===
// Le a URL do formulario. Se vazia ou se o download falhar -> mantem o audio atual (fallback gracioso).
let musicaUrl = '';
try {
  const fdata = $('Formulario de Video').first().json || {};
  musicaUrl = String(fdata['Musica de Fundo (URL)'] || '').trim();
} catch (e) { musicaUrl = ''; }

if (musicaUrl) {
  try {
    const musicPath = `${TMP}/bg_music_${Date.now()}.mp3`;
    // baixa com User-Agent de navegador (mesma abordagem do download da logo)
    await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${musicPath}" "${musicaUrl}"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
    const musicaOk = (function () { try { return fs.existsSync(musicPath) && fs.statSync(musicPath).size > 4096; } catch (e) { return false; } })();
    if (musicaOk) {
      const mixedPath = `${TMP}/final_mix_${Date.now()}.mp4`;
      // -stream_loop -1 faz a musica repetir; volume=0.12 deixa a musica baixa/ambiente;
      // amix duration=first encerra junto com o video; normalize=0 mantem a narracao em volume cheio (dominante);
      // -shortest garante que nao exceda a duracao do video.
      await execAsync(`ffmpeg -y -i "${finalPath}" -stream_loop -1 -i "${musicPath}" -filter_complex "[1:a]volume=0.12[bg];[0:a][bg]amix=inputs=2:duration=first:dropout_transition=2:normalize=0[aout]" -map 0:v -map "[aout]" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -shortest -movflags +faststart "${mixedPath}"`, EXEC_OPTS);
      if (fs.existsSync(mixedPath) && fs.statSync(mixedPath).size > 0) {
        finalPath = mixedPath; // passa a usar a versao com musica
      }
    }
  } catch (e) {
    // qualquer falha no download/mix -> mantem finalPath sem musica (nao quebra o workflow)
  }
}

const finalBuf = fs.readFileSync(finalPath);
const nomeArquivo = `${articleTitle}.mp4`;
return [{
  json: { articleTitle: articleTitle, fileName: nomeArquivo },
  binary: { data: await this.helpers.prepareBinaryData(finalBuf, nomeArquivo, 'video/mp4') }
}];
